     9→ */
    10→
    11→namespace AgentPress;
    12→
    13→use AgentPress\Logger;
    14→
    15→/**
    16→ * Admin class for AgentPress.
    17→ */
    18→class Admin {
    19→
    20→    /**
    21→     * Menu slug for the admin page.
    22→     *
    23→     * @var string
    24→     */
    25→    const MENU_SLUG = 'agentpress';
    26→
    27→    /**
    28→     * Constructor.
    29→     */
    30→    public function __construct() {
    31→        add_action('admin_menu', array($this, 'add_admin_menu'));
    32→        add_action('admin_init', array($this, 'register_settings'));
    33→        add_action('admin_enqueue_scripts', array($this, 'enqueue_admin_scripts'));
    34→    }
    35→
    36→    /**
    37→     * Add the admin menu item.
    38→     */
    39→    public function add_admin_menu() {
    40→        add_submenu_page(
    41→            'tools.php',
    42→            __('AgentPress', 'agentpress'),
    43→            __('AgentPress', 'agentpress'),
    44→            'manage_options',
    45→            self::MENU_SLUG,
    46→            array($this, 'render_admin_page')
    47→        );
    48→    }
    49→
    50→    /**
    51→     * Register plugin settings.
    52→     */
    53→    public function register_settings() {
    54→        register_setting('agentpress_settings', 'agentpress_settings', array($this, 'sanitize_settings'));
    55→
    56→        // API Key field
    57→        add_settings_section(
    58→            'agentpress_api_section',
    59→            __('API Configuration', 'agentpress'),
    60→            array($this, 'render_api_section'),
    61→            'agentpress_settings'
    62→        );
    63→
    64→        add_settings_field(
    65→            'claude_api_key',
    66→            __('Claude API Key', 'agentpress'),
    67→            array($this, 'render_api_key_field'),
    68→            'agentpress_settings',
    69→            'agentpress_api_section'
    70→        );
    71→
    72→        add_settings_field(
    73→            'cf_worker_url',
    74→            __('Cloudflare Worker URL', 'agentpress'),
    75→            array($this, 'render_cf_worker_url_field'),
    76→            'agentpress_settings',
    77→            'agentpress_api_section'
    78→        );
    79→
    80→        add_settings_field(
    81→            'default_model',
    82→            __('Default Model', 'agentpress'),
    83→            array($this, 'render_default_model_field'),
    84→            'agentpress_settings',
    85→            'agentpress_api_section'
    86→        );
    87→    }
    88→
    89→    /**
    90→     * Sanitize settings.
    91→     *
    92→     * @param array $input Raw input settings.
    93→     * @return array Sanitized settings.
    94→     */
    95→    public function sanitize_settings($input) {
    96→        $sanitized = array();
    97→
    98→        // Sanitize Claude API key (password field, just keep as-is)
    99→        if (isset($input['claude_api_key'])) {
   100→            $sanitized['claude_api_key'] = $input['claude_api_key'];
   101→        }
   102→
   103→        // Sanitize Cloudflare Worker URL
   104→        if (isset($input['cf_worker_url'])) {
   105→            $url = esc_url_raw($input['cf_worker_url']);
   106→            if (!empty($url) && filter_var($url, FILTER_VALIDATE_URL)) {
   107→                $sanitized['cf_worker_url'] = $url;
   108→            } else {
   109→                add_settings_error(
   110→                    'agentpress_settings',
   111→                    'cf_worker_url',
   112→                    __('Invalid Cloudflare Worker URL. Please enter a valid URL.', 'agentpress')
   113→                );
   114→                $sanitized['cf_worker_url'] = '';
   115→            }
   116→        }
   117→
   118→        // Sanitize default model
   119→        if (isset($input['default_model'])) {
   120→            $valid_models = array('claude-3-5-sonnet-20241022', 'claude-3-opus-20240229', 'claude-3-sonnet-20240229');
   121→            if (in_array($input['default_model'], $valid_models, true)) {
   122→                $sanitized['default_model'] = $input['default_model'];
   123→            } else {
   124→                $sanitized['default_model'] = 'claude-3-5-sonnet-20241022';
   125→            }
   126→        }
   127→
   128→        return $sanitized;
   129→    }
