     1→<?php
     2→/**
     3→ * AgentPress SEOMeta Agent
     4→ *
     5→ * Generates SEO title tags and meta descriptions using the Claude API.
     6→ *
     7→ * @package AgentPress
     8→ * @since 1.0.0
     9→ */
    10→
    11→namespace AgentPress\Agents;
    12→
    13→use AgentPress\Parser;
    14→
    15→/**
    16→ * SEOMeta agent class.
    17→ */
    18→class SEO_Meta {
    19→
    20→    /**
    21→     * Maximum title length in characters.
    22→     *
    23→     * @var int
    24→     */
    25→    const MAX_TITLE_LENGTH = 60;
    26→
    27→    /**
    28→     * Maximum description length in characters.
    29→     *
    30→     * @var int
    31→     */
    32→    const MAX_DESCRIPTION_LENGTH = 160;
    33→
    34→    /**
    35→     * Default model for SEO generation.
    36→     *
    37→     * @var string
    38→     */
    39→    private static $default_model = 'claude-3-5-sonnet-20241022';
    40→
    41→    /**
    42→     * Run the SEOMeta agent.
    43→     *
    44→     * @param array $payload Payload containing content and focus_keyword.
    45→     * @return array|WP_Error Result with title, description, focus_keyword, or WP_Error on failure.
    46→     */
    47→    public static function run($payload) {
    48→        // Validate required content field
    49→        if (empty($payload['content'])) {
    50→            return new \WP_Error(
    51→                'agentpress_seo_meta_missing_content',
    52→                __('Missing required "content" field.', 'agentpress')
    53→            );
    54→        }
    55→
    56→        // Validate required focus_keyword field
    57→        if (empty($payload['focus_keyword'])) {
    58→            return new \WP_Error(
    59→                'agentpress_seo_meta_missing_focus_keyword',
    60→                __('Missing required "focus_keyword" field.', 'agentpress')
    61→            );
    62→        }
    63→
    64→        $content = sanitize_textarea_field($payload['content']);
    65→        $focus_keyword = sanitize_text_field($payload['focus_keyword']);
    66→
    67→        // Get API key
    68→        $api_key = agentpress_get_setting('claude_api_key');
    69→        if (empty($api_key)) {
    70→            return new \WP_Error(
    71→                'agentpress_missing_api_key',
    72→                __('Claude API key is not configured.', 'agentpress')
    73→            );
    74→        }
    75→
    76→        // Get model from settings
    77→        $model = agentpress_get_setting('default_model', self::$default_model);
    78→
    79→        // Build Claude prompt
    80→        $prompt = self::build_prompt($content, $focus_keyword);
    81→
    82→        // Call Claude API
    83→        $response = self::call_claude_api($api_key, $model, $prompt);
    84→
    85→        if (is_wp_error($response)) {
    86→            return $response;
    87→        }
    88→
    89→        // Extract result from response
    90→        $result = self::extract_result_from_response($response);
    91→
    92→        if (is_wp_error($result)) {
    93→            return $result;
    94→        }
    95→
    96→        // Enforce character limits server-side
    97→        $result = self::enforce_limits($result);
    98→
    99→        return $result;
   100→    }
   101→
   102→    /**
   103→     * Build the prompt for Claude.
   104→     *
   105→     * @param string $content     Page or post content.
   106→     * @param string $focus_keyword Focus keyword for SEO.
   107→     * @return string Formatted prompt.
   108→     */
   109→    private static function build_prompt($content, $focus_keyword) {
   110→        $prompt = "You are an SEO expert. Given the following content and focus keyword, generate an optimized title tag and meta description.\n\n";
   111→        $prompt .= "Content:\n" . $content . "\n\n";
   112→        $prompt .= "Focus Keyword: " . $focus_keyword . "\n\n";
   113→        $prompt .= "Requirements:\n";
   114→        $prompt .= "- Title must be under 60 characters\n";
   115→        $prompt .= "- Meta description must be under 160 characters\n";
   116→        $prompt .= "- Include the focus keyword naturally in both title and description\n";
   117→        $prompt .= "- Make them compelling and click-worthy\n\n";
   118→        $prompt .= "Return your response as a JSON object with this exact structure:\n";
   119→        $prompt .= '{"title": "Your title here", "description": "Your meta description here"}\n\n';
   120→        $prompt .= "Only return the JSON object, no additional text.";
   121→
   122→        return $prompt;
   123→    }
   124→
   125→    /**
   126→     * Call the Claude Messages API.
   127→     *
   128→     * @param string $api_key API key.
   129→     * @param string $model   Model name.
   130→     * @param string $prompt  Prompt text.
   131→     * @return array|WP_Error API response or WP_Error on failure.
   132→     */
   133→    private static function call_claude_api($api_key, $model, $prompt) {
   134→        $url = 'https://api.anthropic.com/v1/messages';
   135→
   136→        $headers = array(
   137→            'Content-Type' => 'application/json',
   138→            'x-api-key' => $api_key,
   139→            'anthropic-version' => '2023-06-01',
   140→        );
   141→
   142→        $body = wp_json_encode(array(
   143→            'model' => $model,
   144→            'max_tokens' => 1024,
   145→            'messages' => array(
   146→                array(
   147→                    'role' => 'user',
   148→                    'content' => $prompt,
   149→                ),
   150→            ),
   151→        ));
   152→
   153→        $response = wp_remote_post($url, array(
   154→            'headers' => $headers,
   155→            'body' => $body,
   156→            'timeout' => 30,
   157→        ));
   158→
   159→        if (is_wp_error($response)) {
   160→            return new \WP_Error(
   161→                'agentpress_api_error',
   162→                sprintf(
   163→                    /* translators: %s: error message */
   164→                    __('API request failed: %s', 'agentpress'),
   165→                    $response->get_error_message()
   166→                )
   167→            );
   168→        }
   169→
   170→        $status_code = wp_remote_retrieve_response_code($response);
   171→        $body = wp_remote_retrieve_body($response);
   172→
   173→        if ($status_code !== 200) {
   174→            $error_data = json_decode($body, true);
   175→            $error_message = isset($error_data['error']) && isset($error_data['error']['message'])
   176→                ? $error_data['error']['message']
   177→                : __('Unknown API error.', 'agentpress');
   178→
   179→            return new \WP_Error(
   180→                'agentpress_api_error',
   181→                sprintf(
   182→                    /* translators: %d: HTTP status code, %s: error message */
   183→                    __('API error %1$d: %2$s', 'agentpress'),
   184→                    $status_code,
   185→                    $error_message
   186→                )
   187→            );
   188→        }
   189→
   190→        return json_decode($body, true);
   191→    }
   192→
   193→    /**
   194→     * Extract result from Claude API response.
   195→     *
   196→     * @param array $response API response.
   197→     * @return array|WP_Error Extracted result or WP_Error on failure.
   198→     */
   199→    private static function extract_result_from_response($response) {
   200→        if (!isset($response['content']) || !is_array($response['content'])) {
   201→            return new \WP_Error(
   202→                'agentpress_invalid_response',
   203→                __('Invalid response format from API.', 'agentpress')
   204→            );
   205→        }
   206→
   207→        // Get text from content blocks
   208→        $text = '';
   209→        foreach ($response['content'] as $block) {
   210→            if (isset($block['type']) && $block['type'] === 'text') {
   211→                $text .= $block['text'];
   212→            }
   213→        }
   214→
   215→        if (empty($text)) {
   216→            return new \WP_Error(
   217→                'agentpress_empty_response',
   218→                __('Empty response from API.', 'agentpress')
   219→            );
   220→        }
   221→
   222→        // Try to extract JSON from the response
   223→        $parsed = Parser::extract_json($text);
   224→        if (is_array($parsed) && isset($parsed['title']) && isset($parsed['description'])) {
   225→            return array(
   226→                'title' => sanitize_text_field($parsed['title']),
   227→                'description' => sanitize_textarea_field($parsed['description']),
   228→            );
   229→        }
   230→
   231→        // If no JSON found, try to parse raw text
   232→        return new \WP_Error(
   233→            'agentpress_invalid_response',
   234→            __('Could not parse title and description from API response.', 'agentpress')
   235→        );
   236→    }
   237→
   238→    /**
   239→     * Enforce character limits on title and description.
   240→     *
   241→     * @param array $result Result array with title and description.
   242→     * @return array Result with enforced limits.
   243→     */
   244→    private static function enforce_limits($result) {
   245→        $title = $result['title'];
   246→        $description = $result['description'];
   247→
   248→        // Truncate title at word boundary if over limit
   249→        if (mb_strlen($title) > self::MAX_TITLE_LENGTH) {
   250→            $title = mb_substr($title, 0, self::MAX_TITLE_LENGTH);
   251→            $last_space = mb_strrpos($title, ' ');
   252→            if ($last_space !== false) {
   253→                $title = mb_substr($title, 0, $last_space);
   254→            }
   255→            $title = rtrim($title, '.,;:!?') . '...';
   256→        }
   257→
   258→        // Truncate description at word boundary if over limit
   259→        if (mb_strlen($description) > self::MAX_DESCRIPTION_LENGTH) {
   260→            $description = mb_substr($description, 0, self::MAX_DESCRIPTION_LENGTH);
   261→            $last_space = mb_strrpos($description, ' ');
   262→            if ($last_space !== false) {
   263→                $description = mb_substr($description, 0, $last_space);
   264→            }
   265→            $description = rtrim($description, '.,;:!?') . '...';
   266→        }
   267→
   268→        return array(
   269→            'title' => $title,
   270→            'description' => $description,
   271→        );
   272→    }
   273→}
   274→
   275→/**
   276→ * Handler function for SEOMeta agent.
   277→ *
   278→ * @param array $payload Payload data.
   279→ * @return array|WP_Error Result or WP_Error.
   280→ */
   281→function agentpress_run_seo_meta($payload) {
   282→    return SEO_Meta::run($payload);
   283→}
